#### Step 3: Create the `WallDrawingInput` component inside `PropertiesPanel.jsx`

Add a new private function component just before the main `PropertiesPanel` export. It takes props: `{ toolState, dispatch, editorDispatch, activeFloorId, u }`.

Key design choices:
- Uses `useState` for: `lengthVal` (string), `degrees` (string), `minutes` (string), `nsDir` ('N'|'S'), `ewDir` ('E'|'W')
- Length and angle inputs are `<input type="text">` (NOT `type="number"`) to avoid browser spinner UX issues and to allow the user to type freely then confirm
- An `onKeyDown` handler on the form catches Enter key and calls the confirm function
- A "Create Wall" button also triggers confirm
- After creating the wall, all inputs except the dropdowns are cleared (length, degrees, minutes reset)
- The start point display uses `InputField` with `readOnly` (existing pattern from `WallProperties`)

Implementation outline:

```jsx
function WallDrawingInput({ toolState, dispatch, editorDispatch, activeFloorId, u }) {
  const [lengthVal, setLengthVal] = useState('');
  const [degrees, setDegrees] = useState('');
  const [minutes, setMinutes] = useState('');
  const [nsDir, setNsDir] = useState('N');
  const [ewDir, setEwDir] = useState('W');
  const lengthRef = useRef(null);

  const start = toolState.start;
  if (!start) return null;

  const handleConfirm = () => {
    const lengthMm = u.fromDisplay(parseFloat(lengthVal));
    const deg = parseInt(degrees, 10) || 0;
    const min = parseInt(minutes, 10) || 0;

    if (!lengthMm || lengthMm < MIN_WALL_LENGTH) return;
    if (deg < 0 || deg > 90 || min < 0 || min >= 60) return;

    const angle = surveyorBearingToSvgAngle(nsDir, deg, min, ewDir);
    const endPt = endpointFromBearing(start, lengthMm, angle);

    const wall = createWall(start, endPt, undefined, {
      startAttachment: toolState.startAttachment || null,
      endAttachment: null,
    });

    dispatch({ type: 'WALL_ADD', floorId: activeFloorId, wall });

    // Chain: end becomes new start
    editorDispatch({
      type: 'UPDATE_TOOL_STATE',
      payload: { start: endPt, startAttachment: null, preview: null },
    });

    // Clear inputs for next segment
    setLengthVal('');
    setDegrees('');
    setMinutes('');

    // Re-focus length input for rapid entry
    setTimeout(() => lengthRef.current?.focus(), 0);
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      handleConfirm();
    }
  };

  return (
    <div>
      <div className={styles.title}>Drawing Wall</div>
      <div className={styles.subtitle}>Start Point</div>
      <InputField label="X" type="number" suffix={u.suffix} value={u.toDisplay(start.x)} readOnly />
      <InputField label="Y" type="number" suffix={u.suffix} value={u.toDisplay(start.y)} readOnly />

      <div className={styles.subtitle}>Bearing</div>
      <div className={styles.bearingRow} onKeyDown={handleKeyDown}>
        <select className={styles.bearingSelect} value={nsDir} onChange={e => setNsDir(e.target.value)}>
          <option value="N">N</option>
          <option value="S">S</option>
        </select>
        <input className={styles.bearingInput} value={degrees} onChange={e => setDegrees(e.target.value)}
               placeholder="deg" />
        <span className={styles.bearingSymbol}>°</span>
        <input className={styles.bearingInput} value={minutes} onChange={e => setMinutes(e.target.value)}
               placeholder="min" style={{ width: '40px' }} />
        <span className={styles.bearingSymbol}>'</span>
        <select className={styles.bearingSelect} value={ewDir} onChange={e => setEwDir(e.target.value)}>
          <option value="E">E</option>
          <option value="W">W</option>
        </select>
      </div>

      <div className={styles.subtitle}>Length</div>
      <div className={styles.field} onKeyDown={handleKeyDown}>
        <input ref={lengthRef} className={styles.bearingInput}
               style={{ width: '100%', textAlign: 'left' }}
               value={lengthVal} onChange={e => setLengthVal(e.target.value)}
               placeholder={u.suffix} />
        <span className={styles.bearingSymbol}>{u.suffix}</span>
      </div>

      <button className={styles.confirmBtn} onClick={handleConfirm}>
        Create Wall (Enter)
      </button>
    </div>
  );
}
```

Note: The `InputField.module.css` styles do NOT need to be imported separately -- the `bearingInput` class defined in `PropertiesPanel.module.css` replicates the same visual style with `font-family: var(--font-blueprint)` and the same border/radius/height as the existing `.input` class.

#### Step 4: Wire `WallDrawingInput` into the PropertiesPanel render logic

